r($,"awk","ajK",()=>A.e4("\uc815\ub2f5 \ud615\uc2dd : \uc601\uc5b4","assets/images/badges/2.png","\uc21c\uc11c\ub300\ub85c \ub098\uc5f4\ud574\ubcf4\uc138\uc694","\uc138\ub85c\ub85c \uc77d\uc5b4\ubcf4\uc138\uc694",!1,"","assets/images/problems/2.jpg","\ub0af\uc775\uc740 \ubb38\uc7a5\ub4e4\uc774 \ubcf4\uc77c\uac70\uc5d0\uc694","\ucf58\uc11c\ud2b8\uc5d0 \ub2e4\ub140\uac00\uc694","<s>\uc5b4 \uc5ec\uae34 \uc5b4\ub514\uc9c0?</s>\n\n\n\n\n\ud070 \uc18c\ub9ac\uac00 \ub4e4\ub824 \ub4a4\ub97c \ub3cc\uc544\ubcf4\ub2c8\n\n\uadf8\uacf3\uc5d0\ub294 \ucf58\uc11c\ud2b8\uc7a5\uc774 \uc788\uc5c8\uc2b5\ub2c8\ub2e4.\n\n\n\n\n\ubab0\ub798 \uc228\uc5b4 \ubc14\ub77c\ubcf8 \ucf58\uc11c\ud2b8\uc7a5\uc758 \ubaa8\uc2b5\uc740 \ud2b9\ubcc4\ud588\uc2b5\ub2c8\ub2e4.\n\n\n\n\n\ubb34\ub300 \uc704\uc5d0 \uc11c\uc11c \ubc1d\uac8c \ube5b\ub098\ub294 \ub2e8 \ud55c \uba85\uc758 \uc0ac\ub78c\uacfc,\n\n\uadf8 \ud55c \uba85\uc744 \ubc14\ub77c\ubcf4\ub294 \uc218\ub9ce\uc740 \uc0ac\ub78c\ub4e4.\n\n\n\n\n\uc791\uc740 \uc704\uc131\uc740 \uc774 \uad11\uacbd\uc744 \ubcf4\uba70,\n\n\ubb34\ub300\ub97c \ubc14\ub77c\ubcf4\ub294 \uc800 \uad00\uac1d\ub4e4\uc774 \uc790\uc2e0\uacfc \uac19\ub2e4\uace0 \ub290\uaf08\uc2b5\ub2c8\ub2e4.\n\n\n\n\n\n\n\n\n",-1))
r($,"awl","ajL",()=>A.e4("\uc815\ub2f5 \ud615\uc2dd : \uc601\uc5b4","assets/images/badges/3.png","\ub192\uc740 \ub3c4\ub294 A\uac00 \uc544\ub2d9\ub2c8\ub2e4","\uc800\ud76c\ub294 \ucd5c\uc120\uc744 \ub2e4\ud588\uc2b5\ub2c8\ub2e4",!1,"","assets/images/problems/3.jpg","\uc0c1\uc9d5\uc0c9\uc774 \uace7 \uc21c\uc11c\uc785\ub2c8\ub2e4","\uc624\ub8e8\uace8 \uc2ec\ud654\ud559\uc2b5\ubc18","<s>\ud589\uc131\uc5d0\uac8c \ub098\ub77c\ub294 \uc874\uc7ac\ub3c4 \uc800 \ub9ce\uc740 \uad00\uac1d \uc911 \ud55c \uba85\uacfc \uac19\uc558\uaca0\uc9c0.</s>\n\n\n\n\n\ubb38\ub4dd \uc2ac\ud37c\uc9c4 \uc791\uc740 \uc704\uc131\uc740 \ucf58\uc11c\ud2b8\uc7a5\uc744 \ub098\uc640 \uae38\uc744 \uac77\uae30 \uc2dc\uc791\ud588\uc2b5\ub2c8\ub2e4. \n\n\n\n\n\uc544\ubb34 \uc0dd\uac01 \uc5c6\uc774 \uac77\uae30\ub9cc \ud558\ub358 \ub3c4\uc911,\n\n\uc5b4\ub514\uc120\uac00 \uc775\uc219\ud55c \ud53c\uc544\ub178 \uc18c\ub9ac\uac00 \ub4e4\ub824\uc654\uc2b5\ub2c8\ub2e4.\n\n\n\n\n\ud589\uc131\uc774 \ub298 \uc791\uc740 \uc704\uc131\uc5d0\uac8c \ubd88\ub7ec\uc8fc\ub358 \ub178\ub798\uc600\uc8e0.\n\n\n\n\n\uc791\uc740 \uc704\uc131\uc740 \ubc1c\uac78\uc74c\uc744 \uba48\ucd94\uace0 \uc790\ub9ac\uc5d0 \uc11c\uc11c\n\n\ud53c\uc544\ub178 \uc18c\ub9ac\ub97c \ub4e3\uae30 \uc2dc\uc791\ud588\uc2b5\ub2c8\ub2e4.\n\n\n\n\n\n\n\n\n",-1))
