r($,"awn","ajN",()=>A.e4("\uc815\ub2f5 \ud615\uc2dd : \ud55c\uae00","assets/images/badges/5.png","\ud604\uc9c4 \uc815\uc740 \uc9c0\uc6b0","?\ud76c\uc9c4 ?\ud604\uc9c4 ?\ud558\uc2ac ... ?\ud61c\uc8fc",!1,"","assets/images/problems/5.jpg","\uc5f4\ub450 \uac1c \uc911 \ud558\ub098\uac00 \ubd80\uc871\ud574\uc694","Everyday I Love You","<f>\uc598 \ub108\ub294 \uc65c \uc6b8\uace0 \uc788\ub2c8?</f>\n\n\n\n\n\uc778\uc790\ud55c \uc778\uc0c1\uc744 \ud55c \uc5ec\uc6b0\uac00 \ub2e4\uac00\uc640 \uc791\uc740 \uc704\uc131\uc5d0\uac8c \ubb3c\uc5c8\uc2b5\ub2c8\ub2e4.\n\n\n\n\n<s>\uc774 \ub178\ub798 \uc544\uc800\uc528\uac00 \uc5f0\uc8fc\ud55c \uac70\uc608\uc694?</s>\n\n\n\n\n<f>\uadf8\ub807\ub2e8\ub2e4. \ud639\uc2dc \uc5f0\uc8fc\uac00 \ub9c8\uc74c\uc5d0 \uc548 \ub4e4\uc5c8\ub2c8?</f>\n\n\n\n\n<s>\uc544\ub2c8\uc5d0\uc694. \uadf8\ub0e5 \uc0dd\uac01\uc774 \ub9ce\uc544\uc84c\uc744 \ubfd0\uc774\uc5d0\uc694.</s>\n\n\n\n\n\n\n\n\n",-1))
r($,"awo","ajO",()=>A.e4("\uc815\ub2f5 \ud615\uc2dd : \uc601\uc5b4","assets/images/badges/6.png","\uc0bc\ub4f1\ubd84\ud558\uc138\uc694","\uc21c\uc11c\ub300\ub85c \ud569\uce58\uc138\uc694",!1,"","assets/images/problems/6.jpg","\uc6d0\ub798 \ubaa8\uc591\uc73c\ub85c \ub418\ub3cc\ub824\ubcf4\uc544\uc694","\ube44\ubc00\uc758 \ube44\ubc00\uc774 \ud480\ub9b4\uac70\uc57c","<f>\uc74c \uadf8\ub7ec\uc9c0 \ub9d0\uace0 \ub098\ub97c \ub530\ub77c\uc640 \ubcfc\ub798?</f>\n\n\n\n\n\uc5ec\uc6b0\ub294 \uc791\uc740 \uc704\uc131\uc744 \ub370\ub9ac\uace0 \uc5b4\ub518\uac00\ub85c \ub5a0\ub0ac\uc2b5\ub2c8\ub2e4.\n\n\n\n\n<f>\uc790, \uc5ec\uae30\ub97c \ubcf4\ub834.</f>\n\n\n\n\n\uc791\uc740 \uc704\uc131\uc758 \ub208\uc55e\uc5d0\ub294 \uc785\uc220\ucc98\ub7fc \ubd89\uc740 \uaf43\ubc2d\uc774 \ud3bc\uccd0\uc838 \uc788\uc5c8\uc2b5\ub2c8\ub2e4.\n\n\n\n\n<f>\uc7a5\ubbf8 \uaf43\ubc2d\uc774\ub780\ub2e4. \uc0dd\uac01\uc774 \ub9ce\uc544\uc9c8 \ub54c\ub9c8\ub2e4 \ub0b4\uac00 \ub298 \ub4e4\ub9ac\ub294 \uacf3\uc774\uc9c0.</f>\n\n\n\n\n\n\n\n\n",-1))
